INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('ea1e26df-e3ef-41d1-a144-cca79a3ca5ec', 'caminhadas', 'Caminhadas', '#27ae60', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('e05ec26e-b193-4ad6-a583-a68ff2cc96f4', 'giros', 'Giros', '#8e44ad', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('34031fa1-c807-476d-ac49-6ec8039aa5d3', 'pescadas', 'Pescadas', '#d35400', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('c04b0646-983b-4875-afe7-c4f9154f62b4', 'inversao', 'Inversão', '#c0392b', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('0bf71140-428a-42c3-960e-d80aa03b181b', 'bases', 'Bases', '#16a085', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('10961377-b4f4-4bac-a1a2-0a7e493ada26', 'outros', 'Outros', '#7f8c8d', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('95682503-9618-4ce6-b355-3dd9895f0ebc', 'footwork', 'Forró Footwork', '#e67e22', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('7a79b48d-fdfc-4b11-8426-6fbec863d99f', 'conceitos', 'Conceitos', '#f39c12', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.categorias (id, name, label, color, inserted_at, updated_at) VALUES ('faead397-31ff-424b-bde0-1ffaf538a8e5', 'convencoes', 'Convenções', '#95a5a6', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.conceitos_tecnicos (id, title, description, inserted_at, updated_at) VALUES ('e788fb93-31ae-4ead-b9d3-449df609b837', 'Intenção de sacada', 'Avanço da perna esquerda do condutor entre as pernas da conduzida sem completar a sacada. Gerada em: IV, PMB, BF. Saídas: SC, GP, TRD, TR, CA.', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.conceitos_tecnicos (id, title, description, inserted_at, updated_at) VALUES ('143f987f-b67d-4f9d-b02e-72959ced8cb2', 'Elástico', 'Tensão bilateral quando ambos jogam o CDM na mesma direção simultaneamente. Usado em TR-ARM e TR-ARM-PE.', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.conceitos_tecnicos (id, title, description, inserted_at, updated_at) VALUES ('a1da4161-a7fc-43ed-bbcd-62322a27fa28', 'Transferência de peso (CDM)', 'Todo movimento começa com transferência de peso. Sem CDM, não há condução — apenas deslocamento mecânico de braços.', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.conceitos_tecnicos (id, title, description, inserted_at, updated_at) VALUES ('76a33a6a-4667-4ae9-bbc2-c60b937fad44', 'Quarto tempo do forró', 'Compasso 2/4. Ciclo base: 3 pisadas + 1 pausa/suspensão. O 4º tempo é o momento de ''decisão'' do corpo. Usado em DA-R.', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.conceitos_tecnicos (id, title, description, inserted_at, updated_at) VALUES ('b10c0457-3af7-44cc-a544-e1c5c20db3f8', 'Frame (quadro)', 'Estrutura de braços, ombros e tronco entre os parceiros. Transmite a intenção do CDM. Rígido demais trava; mole demais perde a informação.', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.conceitos_tecnicos (id, title, description, inserted_at, updated_at) VALUES ('c9bd2994-74e7-4bdd-a53a-8676c0de2198', 'Dissociação', 'Mover tronco e quadril em direções diferentes. Essencial em PU-E-T, giros de 5 pisadas (GM, GPA), IV.', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.conceitos_tecnicos (id, title, description, inserted_at, updated_at) VALUES ('2b6116ef-7941-451b-b430-8064e580be5f', 'Condução por abdômen vs. mãos', 'Dois canais distintos. Abdômen/tronco: mais roots — CDM pela proximidade dos corpos (SCSP). Mãos/braços: mais aberta — DA-R, giros, footwork.', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('992e10e4-529d-4ca0-868d-f98ee92ebd33', NULL, 'Convenções da Notação', NULL, NULL, NULL, 1, 'faead397-31ff-424b-bde0-1ffaf538a8e5', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('42005123-929a-4e0d-aedf-a68e43deef5d', 1, 'Bases', 'B', 'Movimentos essenciais, usados como ponto de partida para combinações.', NULL, 2, '0bf71140-428a-42c3-960e-d80aa03b181b', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('88878dcd-93ae-4441-9573-e8d38483b0be', 2, 'Sacadas', 'SC', 'Movimento de interceptação de espaço ou de perna.', NULL, 3, '5d4ea666-5c49-4c18-ba38-f342b73fa06b', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('ee826713-b055-4e37-a383-6eb9fb633010', 3, 'Sacada sem peso', 'SCSP', NULL, 'A condução parte do abdômen e ombro, não do pé. Sempre com 4 tempos de footwork antes da saída em chassê. Antigo nome: CH (Chutinho) — obsoleto.', 4, '5d4ea666-5c49-4c18-ba38-f342b73fa06b', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('8a96eda9-2463-432b-839e-4cbb90c7840f', 4, 'Travas', 'TR', 'Travamentos de perna, podem ter sacada ou não.', 'Em trava a perna do condutor vai à frente. O V da abertura entre os parceiros não pode ser muito grande.', 5, 'a4c5f003-8785-43bf-988f-a4268c7f80a7', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('7f7e0626-bab2-49eb-837d-2944e16574e8', 5, 'Pescadas', 'PE', 'PE é sempre uma finalização. A entrada é rápida, interceptando o movimento antes que ele se complete.', 'Notação: PE-[perna do condutor]-[perna da conduzida]', 6, '34031fa1-c807-476d-ac49-6ec8039aa5d3', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('d5829130-0198-4d6d-81f2-d6a37ba1d4bd', 6, 'Caminhadas', 'CA', 'Deslocamentos frontais, laterais ou diagonais.', 'A conduzida vai levemente à frente em caminhada — diferente da trava.', 7, 'ea1e26df-e3ef-41d1-a144-cca79a3ca5ec', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('b3176743-4839-4874-8bce-bd5c447b12f6', 7, 'Giro Paulista', 'GP', 'Categoria própria — independente dos giros simples.', 'Todos os paulistas podem sair aberto (-A) ou fechado (-F).', 8, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('3282c992-dba8-4911-962e-6d0fb4b64871', 8, 'Inversão', 'IV', 'Condutor gira a conduzida ao seu redor pela esquerda, mantendo-se no próprio eixo.', 'Sequência: esquerda atrás → direita avança → esquerda à frente. A esquerda à frente gera intenção de sacada. Antigo nome: Facão (FA) — obsoleto.', 9, 'c04b0646-983b-4875-afe7-c4f9154f62b4', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('3d8851f2-d0ca-4d61-b433-1fd6f98599a4', 9, 'Push n pull', 'PU', NULL, NULL, 10, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('cf0aca52-6373-478f-b143-6696a4b3520b', 10, 'Dança aberta', 'DA', 'Duas versões — forró universitário e forró roots. Distintas em mecânica e uso.', NULL, 11, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('9f09fc4d-4562-4e9f-aa47-6269c0cb069a', 11, 'Pião', 'PI', 'Giro conjunto frente a frente. Pode ser inserido em qualquer momento da dança.', 'Eixo central espelhado. Ciclo: 3 passos = 1 volta. Regra do ímpar: saídas técnicas só ficam corretas em voltas ímpares.', 12, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', 12, 'Giros', 'G', 'Categoria secundária na dança atual.', NULL, 13, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('3cd8906c-7cc1-485d-b898-daad533309cb', 13, 'Arrastes', 'AR', NULL, NULL, 14, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('d9325b2a-59de-44a8-b07c-c1f7cf712627', 14, 'Mão nas costas', 'MC', NULL, NULL, 15, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('e67a9293-51ce-4a8d-b34b-26c5e55bb5c6', 15, 'Abraço lateral', 'AB', NULL, NULL, 16, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('e15561c6-f07c-4996-9a87-f525f7c66281', 16, 'Cadena', 'CD', NULL, NULL, 17, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('b17c26cd-d274-4d08-a43f-2d5c8eabd7ab', 17, 'Ginga (extra)', NULL, 'A ginga nunca é uma categoria isolada — é um complemento entre parênteses.', NULL, 18, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('88999d5d-e995-4c8d-a911-a04d1e9437b2', 18, 'Outros movimentos', NULL, NULL, NULL, 19, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('32a63ce8-b06f-4da9-9165-32eacd13f9af', 19, 'Footwork & Variações Únicas', 'HF', 'Passos únicos do @forro_footwork que não se encaixam diretamente nas categorias existentes — musicalidade, decoração, condução ativa ou combinações criativas.', 'Nomes em inglês são os nomes originais do canal @forro_footwork.', 20, '95682503-9618-4ce6-b355-3dd9895f0ebc', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.secoes (id, num, title, code, description, note, "position", category_id, inserted_at, updated_at) VALUES ('1538acfe-0e97-41ff-a7f8-be2c151dae39', NULL, 'Conceitos Técnicos de Condução', NULL, 'Princípios que explicam a lógica por trás dos movimentos — ferramentas de compreensão e condução.', NULL, 21, '7a79b48d-fdfc-4b11-8426-6fbec863d99f', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('a858d39c-dd87-4b90-bcd5-2d95c18dcd75', 'Direção', NULL, 1, '992e10e4-529d-4ca0-868d-f98ee92ebd33', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('a3994e15-468b-4adc-829d-b5e1cd8f4512', 'Pé Duplo', NULL, 2, '992e10e4-529d-4ca0-868d-f98ee92ebd33', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('83618628-a4e2-4cf7-a5be-9baac7b6b77e', 'Saídas de Giros Paulistas', 'Todos os paulistas (GP, GPS, GPE) podem sair aberto ou fechado — sufixos opcionais.', 3, '992e10e4-529d-4ca0-868d-f98ee92ebd33', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('8d341f68-862d-44d9-ad4a-5dd9e16ef731', 'Entradas no GP', NULL, 1, 'b3176743-4839-4874-8bce-bd5c447b12f6', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('c409fa47-0bcd-4208-8422-b3daf1a80089', 'DA-U — Dança aberta universitária', 'Abertura lateral com pé para trás.', 1, 'cf0aca52-6373-478f-b143-6696a4b3520b', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('c02db39a-b680-46bc-9d8f-59291d3091b1', 'DA-R — Dança aberta roots', 'Abertura para frente, usando o quarto tempo do forró. Ativa a intenção de trava via condução firme de mãos e braços.', 2, 'cf0aca52-6373-478f-b143-6696a4b3520b', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('5e779d1b-b6f3-48fd-b9a8-03abb327300b', 'Entradas', NULL, 1, '9f09fc4d-4562-4e9f-aa47-6269c0cb069a', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('fd894700-c225-463c-a419-9064e94b2d65', 'Giros simples', NULL, 1, '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('48440fde-7740-4405-8d9d-5946fd6c8bb2', 'Giros de 5 pisadas', NULL, 2, '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.subsecoes (id, title, note, "position", section_id, inserted_at, updated_at) VALUES ('4e58234a-b50d-4d7b-b5b0-439a82e6af00', 'Variações de giro', NULL, 3, '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
