INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('0e81c5f8-c3e0-48b4-8358-68ea3d0b5e5b', 'pd(ca-fr)', 'Calcanhar → Frente', NULL, false, NULL, 'published', 1, 'faead397-31ff-424b-bde0-1ffaf538a8e5', '992e10e4-529d-4ca0-868d-f98ee92ebd33', 'a3994e15-468b-4adc-829d-b5e1cd8f4512', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('e81f88b2-925c-4102-9e21-e56fb34c1c8c', 'HF-B2TA', 'Base 2 Turn Away', 'Saída pós-caminhada: condutor avança o pé direito e gira anti-horário 360° em 3 tempos. A conduzida reverte naturalmente para base 2.', true, 'images/HF-B2TA.jpg', 'published', 7, 'a4c5f003-8785-43bf-988f-a4268c7f80a7', '8a96eda9-2463-432b-839e-4cbb90c7840f', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('880a499c-cdf9-49e6-b024-b49aa4a5f195', 'HF-R2R', 'Right to Right Block Block Block', 'Conexão mão direita do condutor com mão direita da conduzida, seguida de três bloqueios consecutivos.', true, 'images/HF-R2R.jpg', 'published', 8, 'a4c5f003-8785-43bf-988f-a4268c7f80a7', '8a96eda9-2463-432b-839e-4cbb90c7840f', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
