INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('7912def2-3c3e-48dd-afc7-49b2b49ecef3', 'GCH', 'Giro chicote', NULL, false, NULL, 'published', 4, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '48440fde-7740-4405-8d9d-5946fd6c8bb2', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('7d0a2def-333d-4bad-ac76-54b786b73429', 'HF-MV7', 'Manivela Variation 7 Steps', 'Variação em 7 passos — para quem o giro de 5 ficou simples.', true, 'images/HF-MV7.jpg', 'published', 5, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '48440fde-7740-4405-8d9d-5946fd6c8bb2', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('cf2a1c7c-2d03-4df3-8121-012876edda12', 'HF-WO5', 'Wax On 5 Step Variant', 'Condutor pivota no pé esq. e pisa atrás após o primeiro giro. No passo 2 de 5, mão guia muda para palma direita aberta (''Wax On'').', true, 'images/HF-WO5.jpg', 'published', 6, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '48440fde-7740-4405-8d9d-5946fd6c8bb2', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('170dc520-d60c-4743-8e3e-7ac918ef64d2', 'HF-PT', 'Push Turn', 'Giro de empurrão com mudança de direção — condutor bloqueia no tempo 2, conduzida pivota no pé esq. no tempo 4 e retorna.', true, 'images/HF-PT.jpg', 'published', 1, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('61373477-634d-4362-bead-de644d3bbc8d', 'HF-TAS', 'Turn Away Spin Overhead', 'Logo após um giro: condutor gira no lugar e bloqueia com mão direita por cima. Conduzida gira por baixo do braço.', true, 'images/HF-TAS.jpg', 'published', 2, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('e68fc336-b577-4af6-a0c8-965ed517d829', 'HF-DHS', 'Double Hand Spin', 'Condutor segura as duas mãos durante o giro. Braços caem para os lados ao finalizar.', true, 'images/HF-DHS.jpg', 'published', 3, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('96417894-2673-4e2f-8544-11da22f4444f', 'HF-R2L', 'Right to Left Spin Continuation', 'Saída pós-giro pela mão direita: condutor pega a mão esq. e continua girando em sentido horário.', true, 'images/HF-R2L.jpg', 'published', 4, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('1435a9e0-1f2e-421c-b81c-527c3325a36f', 'HF-CPH', 'Continuation Spin Hand Drop', 'Variação do R2L: após a continuação do giro, a mão da conduzida cai.', true, 'images/HF-CPH.jpg', 'published', 5, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('d522cef2-0c1b-42a6-9e19-1baa201ad1fe', 'HF-HRB', 'High Right Block Spin', 'Após um bloqueio, condutor desce a mão direita pelo braço causando um giro.', true, 'images/HF-HRB.jpg', 'published', 6, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('a71d67bd-de01-458e-98bf-4ca81899074a', 'HF-A5T', 'Avião into 5 Step Turn', 'Avião seguido de giro de 5 passos. Enganosamente complicado.', true, 'images/HF-A5T.jpg', 'published', 7, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('fe97fc49-d3e2-41e7-a3cd-b47e75d5dd2f', 'HF-TAV', 'Turning Avião', 'Avião com rotação — muita coisa acontecendo ao mesmo tempo.', true, 'images/HF-TAV.jpg', 'published', 8, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('f4961650-7d25-4bec-8b30-dacd1ab21bf7', 'HF-SPB', 'The Spin Block', 'Bloqueio combinado com giro — considerado essencial no vocabulário de footwork.', true, 'images/HF-SPB.jpg', 'published', 9, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', '28394cf8-8fa8-4520-bfc7-6fa69e8cb5f4', '4e58234a-b50d-4d7b-b5b0-439a82e6af00', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
