INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('634b2246-db8a-401a-8fc0-61700e996272', 'TRD', 'Trocadilho', 'Saída pós intenção de sacada. Condutor cruza perna direita por trás, conduzida cruza direita pela frente. Entradas: SC, PMB, TR-ARM, CA-CT, IV-CT. Saídas: BF, CA, PI', false, NULL, 'published', 4, '10961377-b4f4-4bac-a1a2-0a7e493ada26', '88999d5d-e995-4c8d-a911-a04d1e9437b2', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('bcec880c-c53c-4bb2-96cf-c5b50c1db940', 'HF-EN', 'Vem Neném', 'Mudança de peso em 6 dos 7 passos — a troca no tempo ''morto'' é contra-intuitiva mas recompensadora.', true, 'images/HF-EN.jpg', 'published', 1, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('7f4226f6-41d8-4d01-aea0-28ff510b959a', 'HF-YNK', 'Yoink', 'O condutor ''rouba'' o pé da conduzida quando o peso dela está no pé de trás.', true, 'images/HF-YNK.jpg', 'published', 2, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('9896d133-2e2d-416f-be59-8542176a487e', 'HF-DD', 'Double Duckerfly', 'Raro e chamativo. Risco de cotovelos no rosto. Exige prática cuidadosa. Duck + butterfly.', true, 'images/HF-DD.jpg', 'published', 3, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('ed4c3149-c806-4383-b917-ea6b78776d4e', 'HF-PS', 'Pequeno Salto', 'Condutor faz um pequeno salto enquanto a conduzida recebe sensação de giro contínuo. Variação de musicalidade.', true, 'images/HF-PS.jpg', 'published', 4, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('2c435fbb-f339-491f-bdd2-a22378e06f62', 'HF-CWB', 'Cowboy Sequence', 'Chicote + laço com spanish exit entre eles. O chicote é o GCH já catalogado.', true, 'images/HF-CWB.jpg', 'published', 5, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('54b49cb2-f6aa-451b-a818-a8ee7a621f1d', 'HF-LF', 'Leader Faint', 'Deco do condutor: entrada como giro simples, mas condutor desliza a mão direita pelas costas até encontrar a mão dela do outro lado.', true, 'images/HF-LF.jpg', 'published', 6, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('7133e5fd-a283-4356-853e-8ca16a53b328', 'HF-TDC', 'Trocadilho do Condutor', '8 tempos. Condutor pausa parte inferior nos tempos 1-2-3 mas guia com o braço. A conduzida lê a abertura do tronco e pisa para a esquerda.', true, 'images/HF-TDC.jpg', 'published', 7, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('845b3575-453f-41d2-bea1-26ec023a14d1', 'HF-AFI', 'Active Follower Intercept', 'A conduzida interrompe ativamente a sugestão do condutor — following ativo.', true, 'images/HF-AFI.jpg', 'published', 8, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('ae0e589f-756e-4df7-bc28-219b4828b52d', 'HF-AWK', 'Armwork for Followers and Leaders', 'Trabalho de braços para conduzidas e condutores. Baseado em masterclass. Não é um passo específico.', true, 'images/HF-AWK.jpg', 'published', 9, '95682503-9618-4ce6-b355-3dd9895f0ebc', '32a63ce8-b06f-4da9-9165-32eacd13f9af', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('8fe447bb-b58a-4ea4-bdd1-2c2cc1b66651', '-FE', 'Saída fechada', NULL, false, NULL, 'published', 2, 'faead397-31ff-424b-bde0-1ffaf538a8e5', '992e10e4-529d-4ca0-868d-f98ee92ebd33', '83618628-a4e2-4cf7-a5be-9baac7b6b77e', '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('5a682eba-bd27-400d-b283-de68737cf88b', 'GP', 'Giro paulista', 'Entradas: DA-R, PI (ímpar), PMB, TR-ARM, AB-GP-D, intenção de sacada. Saídas: qualquer base, PI, CA', false, NULL, 'published', 1, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', 'b3176743-4839-4874-8bce-bd5c447b12f6', NULL, '2026-03-26 14:04:44', '2026-03-26 14:04:44');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('31eb4ec1-b14c-4a1c-b9be-223b62a62bb3', 'BA', 'Balanço', 'Balanço lateral a partir da base frontal. Gera intenção para sacada de esquerda e para arrastes. Momento de suspensão antes da decisão do movimento seguinte.', false, NULL, 'published', 999, '0bf71140-428a-42c3-960e-d80aa03b181b', '42005123-929a-4e0d-aedf-a68e43deef5d', NULL, '2026-04-13 13:18:05', '2026-04-13 13:18:05');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('95357a3a-f0f1-4a8a-9c9e-ab9bb24de39e', 'GPC', 'Giro paulista de costas', 'Paulista executado com os parceiros de costas um para o outro. Exige mais intensidade na condução. Pode ser feito com qualquer mão (esquerda, direita) ou com as duas mãos simultaneamente — neste caso, as mãos geram intensidade para o centro e soltam como um X, criando a rotação. Entrada: GS.', false, NULL, 'published', 999, 'e05ec26e-b193-4ad6-a583-a68ff2cc96f4', 'b3176743-4839-4874-8bce-bd5c447b12f6', NULL, '2026-04-13 13:18:05', '2026-04-13 13:18:05');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('029720aa-a536-432a-909a-bdf9f77dc791', 'SCSP-DA', 'Sacada sem peso na dança aberta', 'Versão aberta da sacada sem peso. Executada em DA-R, retorna à DA-R.', false, NULL, 'published', 999, '5d4ea666-5c49-4c18-ba38-f342b73fa06b', 'ee826713-b055-4e37-a383-6eb9fb633010', NULL, '2026-04-13 13:18:05', '2026-04-13 13:18:05');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('51cb6354-edc6-403e-8c57-11c4fda60e84', 'TR-DA', 'Trava na dança aberta', 'Versão aberta da trava. Executada em DA-R, retorna à DA-R.', false, NULL, 'published', 999, 'a4c5f003-8785-43bf-988f-a4268c7f80a7', '8a96eda9-2463-432b-839e-4cbb90c7840f', NULL, '2026-04-13 13:18:05', '2026-04-13 13:18:05');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('cb037b97-6f43-459e-a4cd-4bc95ea4d402', 'CA-E-DA', 'Caminhada esquerda na dança aberta', 'Versão aberta da caminhada esquerda. Executada em DA-R, retorna à DA-R.', false, NULL, 'published', 999, 'ea1e26df-e3ef-41d1-a144-cca79a3ca5ec', 'd5829130-0198-4d6d-81f2-d6a37ba1d4bd', NULL, '2026-04-13 13:18:05', '2026-04-13 13:18:05');
INSERT INTO public.passos (id, code, name, note, wip, image_path, status, "position", category_id, section_id, subsection_id, inserted_at, updated_at) VALUES ('f104a785-f86e-4d16-b9f3-8a85b595f282', 'DA-R', 'Dança aberta roots', 'Base própria: condutor avança pé esquerdo à frente (em vez de recuar). Saídas: CA-E-DA, TR-DA, SCSP-DA. Footwork em dança aberta ainda em catalogação (ver passos HF-*).', false, NULL, 'published', 1, '10961377-b4f4-4bac-a1a2-0a7e493ada26', 'cf0aca52-6373-478f-b143-6696a4b3520b', 'c02db39a-b680-46bc-9d8f-59291d3091b1', '2026-03-26 14:04:44', '2026-04-13 13:18:05');
